func parsePopCurveGrades(spec string, includeDetails bool) ([]int, error) {
	if strings.TrimSpace(spec) == "" {
		grades := make([]int, 0, 87)
		for i := 1; i <= 70; i++ {
			grades = append(grades, i)
		}
		if includeDetails {
			for i := 82; i <= 98; i++ {
				grades = append(grades, i)
			}
		}
		return grades, nil
	}

	seen := map[int]struct{}{}
	grades := make([]int, 0, 87)
	for _, part := range strings.Split(spec, ",") {
		part = strings.TrimSpace(part)
		if part == "" {
			continue
		}
		bounds := strings.Split(part, "-")
		if len(bounds) != 2 {
			return nil, fmt.Errorf("invalid --grades segment %q (expected n-m)", part)
		}
		start, err := strconv.Atoi(strings.TrimSpace(bounds[0]))
		if err != nil {
			return nil, fmt.Errorf("invalid --grades start %q", bounds[0])
		}
		end, err := strconv.Atoi(strings.TrimSpace(bounds[1]))
		if err != nil {
			return nil, fmt.Errorf("invalid --grades end %q", bounds[1])
		}
		if start > end {
			return nil, fmt.Errorf("invalid --grades segment %q (start > end)", part)
		}
		for i := start; i <= end; i++ {
			if i < 1 || i > 98 || (i > 70 && i < 82) {
				return nil, fmt.Errorf("grade %d is outside supported ranges 1-70 or 82-98", i)
			}
			if _, ok := seen[i]; ok {
				continue
			}
			seen[i] = struct{}{}
			grades = append(grades, i)
		}
	}
	if len(grades) == 0 {
		return nil, fmt.Errorf("no grades selected")
	}
	return grades, nil
}

func buildPopCurveTuples(grades []int, withPlus bool) []popCurveTuple {
	tuples := make([]popCurveTuple, 0, len(grades)*2)
	for _, g := range grades {
		tuples = append(tuples, popCurveTuple{grade: g, plus: false})
		if withPlus && g < 82 {
			tuples = append(tuples, popCurveTuple{grade: g, plus: true})
		}
	}
	return tuples
}

func decodePopCurveFacts(data json.RawMessage, out *map[string]any) error {
	var arr []map[string]any
	if err := json.Unmarshal(data, &arr); err == nil && len(arr) > 0 {
		*out = arr[0]
		return nil
	}
	if err := json.Unmarshal(data, out); err == nil && len(*out) > 0 {
		return nil
	}
	return fmt.Errorf("unable to parse response row")
}

func asString(v any) string {
	if v == nil {
		return ""
	}
	return strings.TrimSpace(fmt.Sprintf("%v", v))
}

func parseIntLoose(v any) int {
	s := asString(v)
	if s == "" {
		return 0
	}
	i, err := strconv.Atoi(s)
	if err == nil {
		return i
	}
	f, ferr := strconv.ParseFloat(s, 64)
	if ferr != nil {
		return 0
	}
	return int(f)
}

func printPopCurveTable(cmd *cobra.Command, rows []map[string]any) {
	tw := newTabWriter(cmd.OutOrStdout())
	fmt.Fprintln(tw, bold("GRADE\tPLUS\tPOP\tPOPHIGHER\tVALID\tMESSAGE"))
	for _, r := range rows {
		msg := asString(r["ServerMessage"])
		if len(msg) > 60 {
			msg = msg[:60] + "..."
		}
		fmt.Fprintf(tw, "%v\t%v\t%v\t%v\t%v\t%s\n",
			r["GradeNo"], r["PlusGrade"], r["Population"], r["PopHigher"], r["IsValidRequest"], msg)
	}
	_ = tw.Flush()
}

